option.value:
param(
    [string]$InputJson = "src/main/resources/db/input/tickets.raw.json",
    [string]$OutputSql = "src/main/resources/db/seed.sql"
)

Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"

if (-not (Test-Path $InputJson)) {
    throw "No existe el JSON de entrada: $InputJson"
}

$tickets = Get-Content -Raw -Encoding UTF8 -Path $InputJson | ConvertFrom-Json
if ($tickets -eq $null -or $tickets.Count -eq 0) {
    throw "El JSON no contiene entradas"
}

# Validacion minima para evitar seeds rotos.
$requiredFields = @("nombre", "apellido", "correo_electronico", "tipo", "pmr", "hash", "numero_local")
foreach ($ticket in $tickets) {
    foreach ($field in $requiredFields) {
        if (-not $ticket.PSObject.Properties.Name.Contains($field)) {
            throw "Falta el campo obligatorio '$field' en una entrada del JSON"
        }
    }
}

function Escape-SqlString([string]$value) {
    if ($null -eq $value) { return "" }
    return $value.Replace("'", "''")
}

$groupedByHash = @{}
foreach ($ticket in $tickets) {
    $hash = [string]$ticket.hash
    if ($groupedByHash.ContainsKey($hash)) {
        throw "Hash duplicado en el JSON: $hash"
    }
    $groupedByHash[$hash] = $ticket
}

$lines = New-Object System.Collections.Generic.List[string]
$lines.Add("SET NAMES utf8mb4;") | Out-Null
$lines.Add("USE qr_app;") | Out-Null
$lines.Add("") | Out-Null
$lines.Add("INSERT INTO event_tickets (nombre, apellido, correo_electronico, tipo, pmr, hash, numero_local)") | Out-Null
$lines.Add("VALUES") | Out-Null

$ordered = $tickets | Sort-Object hash
for ($i = 0; $i -lt $ordered.Count; $i++) {
    $t = $ordered[$i]

    $nombre = Escape-SqlString([string]$t.nombre)
    $apellido = Escape-SqlString([string]$t.apellido)
    $correo = Escape-SqlString([string]$t.correo_electronico)
    $tipo = [int]$t.tipo
    $pmr = if ([bool]$t.pmr) { "TRUE" } else { "FALSE" }
    $hash = Escape-SqlString([string]$t.hash)
    $numeroLocal = [int]$t.numero_local

    $row = "    ('$nombre', '$apellido', '$correo', $tipo, $pmr, '$hash', $numeroLocal)"
    if ($i -lt $ordered.Count - 1) {
        $row += ","
    } else {
        $row += ""
    }
    $lines.Add($row) | Out-Null
}

$lines.Add("ON DUPLICATE KEY UPDATE") | Out-Null
$lines.Add("    nombre = VALUES(nombre),") | Out-Null
$lines.Add("    apellido = VALUES(apellido),") | Out-Null
$lines.Add("    correo_electronico = VALUES(correo_electronico),") | Out-Null
$lines.Add("    tipo = VALUES(tipo),") | Out-Null
$lines.Add("    pmr = VALUES(pmr),") | Out-Null
$lines.Add("    numero_local = VALUES(numero_local);") | Out-Null

$encoding = New-Object System.Text.UTF8Encoding($false)
[System.IO.File]::WriteAllLines((Resolve-Path -Path (Split-Path -Path $OutputSql -Parent)).Path + "\" + (Split-Path -Path $OutputSql -Leaf), $lines, $encoding)

Write-Host "Seed SQL generado en: $OutputSql"
Write-Host "Entradas procesadas:" $ordered.Count

package edu.upc.dsa;

import io.swagger.jaxrs.config.BeanConfig;
import io.swagger.jersey.listing.ApiListingResourceJSON;
import org.glassfish.grizzly.http.server.HttpServer;
import org.glassfish.grizzly.http.server.StaticHttpHandler;
import org.glassfish.jersey.grizzly2.httpserver.GrizzlyHttpServerFactory;
import org.glassfish.jersey.server.ResourceConfig;

import java.io.IOException;
import java.net.URI;

/**
 * Main class.
 *
 */
public class Main {
    // Base URI the Grizzly HTTP server will listen on
    public static final String BASE_URI = "http://localhost:8080/api/";
    //public static final String BASE_URI = "http://192.168.10.92:8080/api/";
    /**
     * Starts Grizzly HTTP server exposing JAX-RS resources defined in this application.
     * @return Grizzly HTTP server.
     */
    public static HttpServer startServer() {
        // create a resource config that scans for JAX-RS resources and providers
        // in edu.upc.dsa package
        final ResourceConfig rc = new ResourceConfig().packages("edu.upc.dsa.services");

        rc.register(io.swagger.jaxrs.listing.ApiListingResource.class);
        rc.register(io.swagger.jaxrs.listing.SwaggerSerializers.class);

        BeanConfig beanConfig = new BeanConfig();

        beanConfig.setHost("localhost:8080");
        //beanConfig.setHost("dsa1.upc.edu");
        beanConfig.setBasePath("/api");
        beanConfig.setContact("support@example.com");
        beanConfig.setDescription("REST API for Tracks Manager");
        beanConfig.setLicenseUrl("http://www.apache.org/licenses/LICENSE-2.0.html");
        beanConfig.setResourcePackage("edu.upc.dsa.services");
        beanConfig.setTermsOfServiceUrl("http://www.example.com/resources/eula");
        beanConfig.setTitle("REST API");
        beanConfig.setVersion("1.0.0");
        beanConfig.setScan(true);

        // create and start a new instance of grizzly http server
        // exposing the Jersey application at BASE_URI
        return GrizzlyHttpServerFactory.createHttpServer(URI.create(BASE_URI), rc);
    }


    /**
     * Main method.
     * @param args
     * @throws IOException
     */
    public static void main(String[] args) throws IOException {
        final HttpServer server = startServer();

        StaticHttpHandler staticHttpHandler = new StaticHttpHandler("./public/");
        server.getServerConfiguration().addHttpHandler(staticHttpHandler, "/");


        System.out.println(String.format("Jersey app started with WADL available at "
                + "%sapplication.wadl\nHit enter to stop it...", BASE_URI));

        System.in.read();
        server.stop();
    }
}

package edu.upc.dsa;

import io.swagger.jaxrs.config.BeanConfig;
import org.glassfish.grizzly.http.server.HttpServer;
import org.glassfish.grizzly.http.server.StaticHttpHandler;
import org.glassfish.jersey.grizzly2.httpserver.GrizzlyHttpServerFactory;
import org.glassfish.jersey.server.ResourceConfig;

import java.net.URI;

/**
 * Main class.
 *
 */
public class Main {
    // Base URI the Grizzly HTTP server will listen on
    public static final String BASE_URI = buildBaseUri();
    /**
     * Starts Grizzly HTTP server exposing JAX-RS resources defined in this application.
     * @return Grizzly HTTP server.
     */
    public static HttpServer startServer() {
        // Only expose the new event-access API modules.
        final ResourceConfig rc = new ResourceConfig().packages("edu.upc.dsa.event");

        rc.register(io.swagger.jaxrs.listing.ApiListingResource.class);
        rc.register(io.swagger.jaxrs.listing.SwaggerSerializers.class);

        BeanConfig beanConfig = new BeanConfig();

        beanConfig.setHost(resolveSwaggerHost());
        beanConfig.setBasePath("/api");
        beanConfig.setContact("support@example.com");
        beanConfig.setDescription("REST API para acceso y verificacion de entradas mediante QR");
        beanConfig.setLicenseUrl("http://www.apache.org/licenses/LICENSE-2.0.html");
        beanConfig.setResourcePackage("edu.upc.dsa.event.services");
        beanConfig.setTermsOfServiceUrl("http://www.example.com/resources/eula");
        beanConfig.setTitle("QR Event Access API");
        beanConfig.setVersion("1.0.0");
        beanConfig.setScan(true);

        // create and start a new instance of grizzly http server
        // exposing the Jersey application at BASE_URI
        return GrizzlyHttpServerFactory.createHttpServer(URI.create(BASE_URI), rc);
    }


    /**
     * Main method.
     * @param args argumentos de inicio
     * @throws InterruptedException si el hilo principal se interrumpe
     */
    public static void main(String[] args) throws InterruptedException {
        final HttpServer server = startServer();

        StaticHttpHandler staticHttpHandler = new StaticHttpHandler("./public/");
        server.getServerConfiguration().addHttpHandler(staticHttpHandler, "/");

        Runtime.getRuntime().addShutdownHook(new Thread(server::shutdownNow));

        System.out.println("Jersey app started with WADL available at "
                + BASE_URI + "application.wadl");

        Thread.currentThread().join();
    }

    private static String buildBaseUri() {
        String host = readHost();
        int port = readPort();
        return "http://" + host + ":" + port + "/api/";
    }

    private static String resolveSwaggerHost() {
        String externalHostname = System.getenv("RENDER_EXTERNAL_HOSTNAME");
        if (externalHostname != null && !externalHostname.trim().isEmpty()) {
            return externalHostname.trim();
        }
        return "localhost:" + readPort();
    }

    private static int readPort() {
        String rawPort = System.getenv("PORT");
        if (rawPort == null || rawPort.trim().isEmpty()) {
            return 8080;
        }
        try {
            return Integer.parseInt(rawPort.trim());
        } catch (NumberFormatException ex) {
            return 8080;
        }
    }

    private static String readHost() {
        String value = System.getenv("HOST");
        if (value == null || value.trim().isEmpty()) {
            return "0.0.0.0";
        }
        return value.trim();
    }
}

package edu.upc.dsa.event.config;

import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;
import java.sql.Statement;

public final class DatabaseConfig {

    private static final String DEFAULT_HOST = "127.0.0.1";
    private static final String DEFAULT_PORT = "3306";
    private static final String DEFAULT_DB = "qr_app";
    private static final String DEFAULT_USER = "root";
    private static final String DEFAULT_PASS = "root";

    private DatabaseConfig() {
    }

    public static Connection getConnection() throws SQLException {
        String host = read("DB_HOST", DEFAULT_HOST);
        String port = read("DB_PORT", DEFAULT_PORT);
        String db = DEFAULT_DB;
        String user = read("DB_USER", DEFAULT_USER);
        String pass = read("DB_PASS", DEFAULT_PASS);

        String jdbcUrl = "jdbc:mariadb://" + host + ":" + port + "/" + db +
                "?createDatabaseIfNotExist=true&useUnicode=true&characterEncoding=utf8";
        Connection connection = DriverManager.getConnection(jdbcUrl, user, pass);
        try (Statement statement = connection.createStatement()) {
            statement.execute("SET NAMES utf8mb4");
        }
        return connection;
    }

    private static String read(String key, String fallback) {
        String fromProperty = System.getProperty(key);
        if (fromProperty != null && !fromProperty.trim().isEmpty()) {
            return fromProperty.trim();
        }
        String fromEnv = System.getenv(key);
        if (fromEnv != null && !fromEnv.trim().isEmpty()) {
            return fromEnv.trim();
        }
        return fallback;
    }
}

package edu.upc.dsa.event.config;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.nio.charset.StandardCharsets;
import java.sql.Connection;
import java.sql.DatabaseMetaData;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;

public final class DatabaseInitializer {

    private DatabaseInitializer() {
    }

    public static void initialize() throws SQLException {
        executeSqlScript("db/schema.sql");
        ensureTicketTableCompatibility();
        executeSqlScript("db/seed.sql");
    }

    private static void ensureTicketTableCompatibility() throws SQLException {
        try (Connection connection = DatabaseConfig.getConnection()) {
            ensureColumn(connection, "event_tickets", "consumed", "BOOLEAN NOT NULL DEFAULT FALSE");
            ensureColumn(connection, "event_tickets", "consumed_at", "DATETIME NULL");
            ensureColumn(connection, "event_tickets", "created_at", "DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP");
        }
    }

    private static void ensureColumn(Connection connection, String table, String column, String definition) throws SQLException {
        if (columnExists(connection, table, column)) {
            return;
        }

        try (Statement statement = connection.createStatement()) {
            statement.execute("ALTER TABLE " + table + " ADD COLUMN " + column + " " + definition);
        }
    }

    private static boolean columnExists(Connection connection, String table, String column) throws SQLException {
        DatabaseMetaData metaData = connection.getMetaData();
        try (ResultSet columns = metaData.getColumns(connection.getCatalog(), null, table, column)) {
            return columns.next();
        }
    }

    private static void executeSqlScript(String classpathResource) throws SQLException {
        String script = readClasspathResource(classpathResource);
        String[] statements = script.split(";");

        try (Connection connection = DatabaseConfig.getConnection();
             Statement statement = connection.createStatement()) {
            for (String rawStatement : statements) {
                String sql = rawStatement.trim();
                if (sql.isEmpty()) {
                    continue;
                }
                if (sql.startsWith("--") || sql.startsWith("#")) {
                    continue;
                }
                statement.execute(sql);
            }
        }
    }

    private static String readClasspathResource(String path) {
        InputStream stream = DatabaseInitializer.class.getClassLoader().getResourceAsStream(path);
        if (stream == null) {
            throw new IllegalStateException("No se encontro el recurso SQL: " + path);
        }

        StringBuilder content = new StringBuilder();
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(stream, StandardCharsets.UTF_8))) {
            String line;
            while ((line = reader.readLine()) != null) {
                content.append(line).append('\n');
            }
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo leer el recurso SQL: " + path, ex);
        }

        return content.toString();
    }
}

package edu.upc.dsa.event.config;

public final class PersistenceProvider {

    private PersistenceProvider() {
    }

    public static boolean isMongo() {
        String provider = read("DB_PROVIDER", "sql");
        String normalized = provider.toLowerCase();
        return "mongo".equals(normalized) || "mongodb".equals(normalized);
    }

    private static String read(String key, String fallback) {
        String fromProperty = System.getProperty(key);
        if (fromProperty != null && !fromProperty.trim().isEmpty()) {
            return fromProperty.trim();
        }
        String fromEnv = System.getenv(key);
        if (fromEnv != null && !fromEnv.trim().isEmpty()) {
            return fromEnv.trim();
        }
        return fallback;
    }
}

