package edu.upc.dsa.event.model;

import javax.xml.bind.annotation.XmlAccessType;
import javax.xml.bind.annotation.XmlAccessorType;
import javax.xml.bind.annotation.XmlElement;
import javax.xml.bind.annotation.XmlRootElement;

@XmlRootElement(name = "entrada")
@XmlAccessorType(XmlAccessType.FIELD)
public class Ticket {

    private String nombre;
    private String apellido;

    @XmlElement(name = "correo_electronico")
    private String correoElectronico;

    private int tipo;
    private boolean pmr;
    private String hash;

    @XmlElement(name = "numero_local")
    private int numeroLocal;

    private boolean consumed;

    @XmlElement(name = "consumed_at")
    private String consumedAt;

    public Ticket() {
    }

    public Ticket(String nombre, String apellido, String correoElectronico, int tipo, boolean pmr, String hash, int numeroLocal, boolean consumed) {
        this(nombre, apellido, correoElectronico, tipo, pmr, hash, numeroLocal, consumed, null);
    }

    public Ticket(String nombre, String apellido, String correoElectronico, int tipo, boolean pmr, String hash, int numeroLocal, boolean consumed, String consumedAt) {
        this.nombre = nombre;
        this.apellido = apellido;
        this.correoElectronico = correoElectronico;
        this.tipo = tipo;
        this.pmr = pmr;
        this.hash = hash;
        this.numeroLocal = numeroLocal;
        this.consumed = consumed;
        this.consumedAt = consumedAt;
    }

    public String getNombre() {
        return nombre;
    }

    public void setNombre(String nombre) {
        this.nombre = nombre;
    }

    public String getApellido() {
        return apellido;
    }

    public void setApellido(String apellido) {
        this.apellido = apellido;
    }

    public String getCorreoElectronico() {
        return correoElectronico;
    }

    public void setCorreoElectronico(String correoElectronico) {
        this.correoElectronico = correoElectronico;
    }

    public int getTipo() {
        return tipo;
    }

    public void setTipo(int tipo) {
        this.tipo = tipo;
    }

    public boolean isPmr() {
        return pmr;
    }

    public void setPmr(boolean pmr) {
        this.pmr = pmr;
    }

    public String getHash() {
        return hash;
    }

    public void setHash(String hash) {
        this.hash = hash;
    }

    public int getNumeroLocal() {
        return numeroLocal;
    }

    public void setNumeroLocal(int numeroLocal) {
        this.numeroLocal = numeroLocal;
    }

    public boolean isConsumed() {
        return consumed;
    }

    public void setConsumed(boolean consumed) {
        this.consumed = consumed;
    }

    public String getConsumedAt() {
        return consumedAt;
    }

    public void setConsumedAt(String consumedAt) {
        this.consumedAt = consumedAt;
    }
}

package edu.upc.dsa.event.repository;

import edu.upc.dsa.event.model.Ticket;

import java.sql.SQLException;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

public class InMemoryTicketRepository implements TicketRepository {

    private final Map<String, Ticket> tickets = new ConcurrentHashMap<String, Ticket>();

    public void upsert(Ticket ticket) {
        tickets.put(ticket.getHash(), ticket);
    }

    @Override
    public Optional<Ticket> findByHash(String hash) throws SQLException {
        Ticket ticket = tickets.get(hash);
        if (ticket == null) {
            return Optional.empty();
        }
        return Optional.of(copy(ticket));
    }

    @Override
    public List<Ticket> findAll() throws SQLException {
        return sortAndCopy(tickets.values());
    }

    @Override
    public List<Ticket> findByEmail(String email) throws SQLException {
        List<Ticket> result = new ArrayList<Ticket>();
        for (Ticket ticket : tickets.values()) {
            if (ticket.getCorreoElectronico().equals(email)) {
                result.add(copy(ticket));
            }
        }
        Collections.sort(result, byHash());
        return result;
    }

    @Override
    public List<Ticket> findByConsumed(boolean consumed) throws SQLException {
        List<Ticket> result = new ArrayList<Ticket>();
        for (Ticket ticket : tickets.values()) {
            if (ticket.isConsumed() == consumed) {
                result.add(copy(ticket));
            }
        }
        Collections.sort(result, byHash());
        return result;
    }

    @Override
    public boolean markConsumed(String hash) throws SQLException {
        Ticket ticket = tickets.get(hash);
        if (ticket == null || ticket.isConsumed()) {
            return false;
        }
        ticket.setConsumed(true);
        ticket.setConsumedAt(Instant.now().toString());
        return true;
    }

    private Ticket copy(Ticket source) {
        return new Ticket(
                source.getNombre(),
                source.getApellido(),
                source.getCorreoElectronico(),
                source.getTipo(),
                source.isPmr(),
                source.getHash(),
                source.getNumeroLocal(),
                source.isConsumed(),
                source.getConsumedAt()
        );
    }

    private List<Ticket> sortAndCopy(Iterable<Ticket> source) {
        List<Ticket> result = new ArrayList<Ticket>();
        for (Ticket ticket : source) {
            result.add(copy(ticket));
        }
        Collections.sort(result, byHash());
        return result;
    }

    private Comparator<Ticket> byHash() {
        return new Comparator<Ticket>() {
            @Override
            public int compare(Ticket a, Ticket b) {
                return a.getHash().compareTo(b.getHash());
            }
        };
    }
}

package edu.upc.dsa.event.repository;

import edu.upc.dsa.event.config.DatabaseConfig;
import edu.upc.dsa.event.model.Ticket;

import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

public class JdbcTicketRepository implements TicketRepository {

    private static final String BASE_SELECT = "SELECT nombre, apellido, correo_electronico, tipo, pmr, hash, numero_local, consumed, consumed_at FROM event_tickets";

    @Override
    public Optional<Ticket> findByHash(String hash) throws SQLException {
        String sql = BASE_SELECT + " WHERE hash = ?";

        try (Connection connection = DatabaseConfig.getConnection();
             PreparedStatement statement = connection.prepareStatement(sql)) {
            statement.setString(1, hash);
            try (ResultSet rs = statement.executeQuery()) {
                if (!rs.next()) {
                    return Optional.empty();
                }
                return Optional.of(mapTicket(rs));
            }
        }
    }

    @Override
    public List<Ticket> findAll() throws SQLException {
        return queryList(BASE_SELECT + " ORDER BY hash ASC");
    }

    @Override
    public List<Ticket> findByEmail(String email) throws SQLException {
        return queryList(BASE_SELECT + " WHERE correo_electronico = ? ORDER BY hash ASC", email);
    }

    @Override
    public List<Ticket> findByConsumed(boolean consumed) throws SQLException {
        return queryList(BASE_SELECT + " WHERE consumed = ? ORDER BY hash ASC", consumed);
    }

    @Override
    public boolean markConsumed(String hash) throws SQLException {
        String updateSql = "UPDATE event_tickets SET consumed = 1, consumed_at = CURRENT_TIMESTAMP " +
                "WHERE hash = ? AND consumed = 0";

        try (Connection connection = DatabaseConfig.getConnection();
             PreparedStatement statement = connection.prepareStatement(updateSql)) {
            statement.setString(1, hash);
            return statement.executeUpdate() == 1;
        }
    }

    private List<Ticket> queryList(String sql, Object... params) throws SQLException {
        List<Ticket> tickets = new ArrayList<Ticket>();
        try (Connection connection = DatabaseConfig.getConnection();
             PreparedStatement statement = connection.prepareStatement(sql)) {
            bindParams(statement, params);
            try (ResultSet rs = statement.executeQuery()) {
                while (rs.next()) {
                    tickets.add(mapTicket(rs));
                }
            }
        }
        return tickets;
    }

    private void bindParams(PreparedStatement statement, Object... params) throws SQLException {
        for (int i = 0; i < params.length; i++) {
            Object param = params[i];
            int index = i + 1;
            if (param instanceof Boolean) {
                statement.setBoolean(index, (Boolean) param);
            } else {
                statement.setObject(index, param);
            }
        }
    }

    private Ticket mapTicket(ResultSet rs) throws SQLException {
        return new Ticket(
                rs.getString("nombre"),
                rs.getString("apellido"),
                rs.getString("correo_electronico"),
                rs.getInt("tipo"),
                rs.getBoolean("pmr"),
                rs.getString("hash"),
                rs.getInt("numero_local"),
                rs.getBoolean("consumed"),
                rs.getTimestamp("consumed_at") == null ? null : rs.getTimestamp("consumed_at").toInstant().toString()
        );
    }
}

package edu.upc.dsa.event.repository;

import com.mongodb.MongoException;
import com.mongodb.MongoClient;
import com.mongodb.MongoClientURI;
import com.mongodb.client.FindIterable;
import com.mongodb.client.MongoCollection;
import com.mongodb.client.MongoDatabase;
import com.mongodb.client.model.Filters;
import com.mongodb.client.model.FindOneAndUpdateOptions;
import com.mongodb.client.model.ReturnDocument;
import com.mongodb.client.model.Sorts;
import com.mongodb.client.model.Updates;
import edu.upc.dsa.event.model.Ticket;
import org.bson.Document;
import org.bson.conversions.Bson;

import java.sql.SQLException;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import java.util.TimeZone;
import java.util.Optional;

public class MongoTicketRepository implements TicketRepository {

    private static final String DEFAULT_DB = "qr_app";
    private static final String DEFAULT_COLLECTION = "event_tickets";

    private static MongoClient sharedClient;

    private final MongoCollection<Document> collection;

    public MongoTicketRepository() {
        this.collection = resolveCollection();
    }

    @Override
    public Optional<Ticket> findByHash(String hash) throws SQLException {
        try {
            Document doc = collection.find(Filters.eq("hash", hash)).first();
            if (doc == null) {
                return Optional.empty();
            }
            return Optional.of(mapTicket(doc));
        } catch (MongoException ex) {
            throw new SQLException("Error en MongoDB al buscar por hash", ex);
        }
    }

    @Override
    public List<Ticket> findAll() throws SQLException {
        try {
            FindIterable<Document> docs = collection.find().sort(Sorts.ascending("hash"));
            return mapList(docs);
        } catch (MongoException ex) {
            throw new SQLException("Error en MongoDB al listar entradas", ex);
        }
    }

    @Override
    public List<Ticket> findByEmail(String email) throws SQLException {
        try {
            FindIterable<Document> docs = collection.find(Filters.eq("correo_electronico", email)).sort(Sorts.ascending("hash"));
            return mapList(docs);
        } catch (MongoException ex) {
            throw new SQLException("Error en MongoDB al listar por correo", ex);
        }
    }

    @Override
    public List<Ticket> findByConsumed(boolean consumed) throws SQLException {
        try {
            FindIterable<Document> docs = collection.find(consumedFilter(consumed)).sort(Sorts.ascending("hash"));
            return mapList(docs);
        } catch (MongoException ex) {
            throw new SQLException("Error en MongoDB al listar por estado", ex);
        }
    }

    @Override
    public boolean markConsumed(String hash) throws SQLException {
        try {
            Document updated = collection.findOneAndUpdate(
                    Filters.and(Filters.eq("hash", hash), consumedFilter(false)),
                    Updates.combine(
                            Updates.set("consumed", true),
                            Updates.set("consumed_at", new Date())
                    ),
                    new FindOneAndUpdateOptions().returnDocument(ReturnDocument.AFTER)
            );
            return updated != null;
        } catch (MongoException ex) {
            throw new SQLException("Error en MongoDB al consumir la entrada", ex);
        }
    }

    private Bson consumedFilter(boolean consumed) {
        if (consumed) {
            return Filters.eq("consumed", true);
        }

        // Documentos importados sin `consumed` se consideran no usados.
        return Filters.or(
                Filters.eq("consumed", false),
                Filters.exists("consumed", false)
        );
    }

    private List<Ticket> mapList(FindIterable<Document> docs) {
        List<Ticket> tickets = new ArrayList<Ticket>();
        for (Document doc : docs) {
            tickets.add(mapTicket(doc));
        }
        return tickets;
    }

    private Ticket mapTicket(Document doc) {
        String nombre = readString(doc, "nombre");
        String apellido = readString(doc, "apellido");
        String correo = readString(doc, "correo_electronico");
        int tipo = readInt(doc, "tipo");
        boolean pmr = readBoolean(doc, "pmr");
        String hash = readString(doc, "hash");
        int numeroLocal = readInt(doc, "numero_local");
        boolean consumed = readBoolean(doc, "consumed");
        String consumedAt = readDate(doc, "consumed_at");

        return new Ticket(nombre, apellido, correo, tipo, pmr, hash, numeroLocal, consumed, consumedAt);
    }

    private String readString(Document doc, String key) {
        Object value = doc.get(key);
        return value == null ? "" : String.valueOf(value);
    }

    private int readInt(Document doc, String key) {
        Object value = doc.get(key);
        if (value instanceof Number) {
            return ((Number) value).intValue();
        }
        if (value == null) {
            return 0;
        }
        try {
            return Integer.parseInt(String.valueOf(value));
        } catch (NumberFormatException ex) {
            return 0;
        }
    }

    private boolean readBoolean(Document doc, String key) {
        Object value = doc.get(key);
        if (value instanceof Boolean) {
            return (Boolean) value;
        }
        if (value == null) {
            return false;
        }
        return Boolean.parseBoolean(String.valueOf(value));
    }

    private String readDate(Document doc, String key) {
        Object value = doc.get(key);
        if (value == null) {
            return null;
        }
        if (value instanceof Date) {
            SimpleDateFormat format = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSSXXX");
            format.setTimeZone(TimeZone.getTimeZone("UTC"));
            return format.format((Date) value);
        }
        return String.valueOf(value);
    }

    private MongoCollection<Document> resolveCollection() {
        String uri = readRequired("MONGO_URI");
        String dbName = read("MONGO_DB", DEFAULT_DB);
        String collectionName = read("MONGO_COLLECTION", DEFAULT_COLLECTION);

        synchronized (MongoTicketRepository.class) {
            if (sharedClient == null) {
                sharedClient = new MongoClient(new MongoClientURI(uri));
            }
        }

        MongoDatabase db = sharedClient.getDatabase(dbName);
        return db.getCollection(collectionName);
    }

    private String read(String key, String fallback) {
        String fromProperty = System.getProperty(key);
        if (fromProperty != null && !fromProperty.trim().isEmpty()) {
            return fromProperty.trim();
        }
        String fromEnv = System.getenv(key);
        if (fromEnv != null && !fromEnv.trim().isEmpty()) {
            return fromEnv.trim();
        }
        return fallback;
    }

    private String readRequired(String key) {
        String value = read(key, null);
        if (value == null || value.trim().isEmpty()) {
            throw new IllegalStateException("Falta la variable obligatoria: " + key);
        }
        return value.trim();
    }
}

package edu.upc.dsa.event.repository;

import edu.upc.dsa.event.model.Ticket;

import java.sql.SQLException;
import java.util.List;
import java.util.Optional;

public interface TicketRepository {

    Optional<Ticket> findByHash(String hash) throws SQLException;

    List<Ticket> findAll() throws SQLException;

    List<Ticket> findByEmail(String email) throws SQLException;

    List<Ticket> findByConsumed(boolean consumed) throws SQLException;

    boolean markConsumed(String hash) throws SQLException;
}

package edu.upc.dsa.event.service;

import edu.upc.dsa.event.exception.ApiException;
import edu.upc.dsa.event.model.Ticket;
import edu.upc.dsa.event.repository.TicketRepository;

import java.sql.SQLException;
import java.util.List;
import java.util.Optional;

public class EventManager {

    private final TicketRepository ticketRepository;

    public EventManager(TicketRepository ticketRepository) {
        this.ticketRepository = ticketRepository;
    }

    public Ticket verify(String hash) throws SQLException {
        validateHash(hash);
        Optional<Ticket> ticket = ticketRepository.findByHash(hash);
        if (!ticket.isPresent()) {
            throw new ApiException(404, "TICKET_NOT_FOUND", "No existe ninguna entrada para este QR");
        }
        return ticket.get();
    }

    public Ticket enter(String hash) throws SQLException {
        Ticket ticket = verify(hash);
        if (ticket.isConsumed()) {
            throw new ApiException(409, "ALREADY_USED", "La entrada ya ha sido validada anteriormente");
        }

        boolean updated = ticketRepository.markConsumed(hash);
        if (!updated) {
            throw new ApiException(409, "ALREADY_USED", "La entrada ya ha sido validada anteriormente");
        }

        return verify(hash);
    }

    public List<Ticket> listAllTickets() throws SQLException {
        return ticketRepository.findAll();
    }

    public List<Ticket> listTicketsByEmail(String email) throws SQLException {
        validateEmail(email);
        return ticketRepository.findByEmail(email.trim());
    }

    public List<Ticket> listUsedTickets() throws SQLException {
        return ticketRepository.findByConsumed(true);
    }

    public List<Ticket> listUnusedTickets() throws SQLException {
        return ticketRepository.findByConsumed(false);
    }

    private void validateHash(String hash) {
        if (hash == null || hash.trim().isEmpty()) {
            throw new ApiException(400, "INVALID_HASH", "El hash del QR es obligatorio");
        }
    }

    private void validateEmail(String email) {
        if (email == null || email.trim().isEmpty()) {
            throw new ApiException(400, "INVALID_EMAIL", "El correo electronico es obligatorio");
        }
    }
}

package edu.upc.dsa.event.services;

import edu.upc.dsa.event.config.TicketRepositoryFactory;
import edu.upc.dsa.event.exception.ApiException;
import edu.upc.dsa.event.model.Ticket;
import edu.upc.dsa.event.service.EventManager;
import io.swagger.annotations.Api;
import io.swagger.annotations.ApiOperation;
import io.swagger.annotations.ApiResponse;
import io.swagger.annotations.ApiResponses;

import javax.ws.rs.GET;
import javax.ws.rs.Path;
import javax.ws.rs.PathParam;
import javax.ws.rs.Produces;
import javax.ws.rs.core.GenericEntity;
import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;
import java.sql.SQLException;
import java.util.List;

@Api(value = "/event", description = "Acceso y verificacion de entradas de evento")
@Path("/event")
@Produces(MediaType.APPLICATION_JSON)
public class EventService {

    private volatile EventManager eventManager;

    public EventService() {
        this(null);
    }

    EventService(EventManager eventManager) {
        this.eventManager = eventManager;
    }

    @GET
    @Path("/verify/{hash}")
    @ApiOperation(value = "Consulta una entrada por hash sin consumirla")
    @ApiResponses({
            @ApiResponse(code = 200, message = "Entrada encontrada", response = Ticket.class),
            @ApiResponse(code = 404, message = "Entrada no encontrada")
    })
    public Response verify(@PathParam("hash") String hash) {
        try {
            Ticket ticket = manager().verify(hash);
            return Response.ok(ticket).build();
        } catch (SQLException ex) {
            throw dbError(ex, "Error al consultar la base de datos");
        }
    }

    @GET
    @Path("/enter/{hash}")
    @ApiOperation(value = "Valida el acceso y consume la entrada")
    @ApiResponses({
            @ApiResponse(code = 200, message = "Entrada validada", response = Ticket.class),
            @ApiResponse(code = 404, message = "Entrada no encontrada"),
            @ApiResponse(code = 409, message = "Entrada ya usada")
    })
    public Response enter(@PathParam("hash") String hash) {
        try {
            Ticket ticket = manager().enter(hash);
            return Response.ok(ticket).build();
        } catch (SQLException ex) {
            throw dbError(ex, "Error al actualizar la base de datos");
        }
    }

    @GET
    @Path("/tickets")
    @ApiOperation(value = "Lista todas las entradas")
    @ApiResponses({
            @ApiResponse(code = 200, message = "Listado de entradas", response = Ticket.class, responseContainer = "List")
    })
    public Response listAllTickets() {
        try {
            List<Ticket> tickets = manager().listAllTickets();
            GenericEntity<List<Ticket>> entity = new GenericEntity<List<Ticket>>(tickets) {
            };
            return Response.ok(entity).build();
        } catch (SQLException ex) {
            throw dbError(ex, "Error al consultar la base de datos");
        }
    }

    @GET
    @Path("/tickets/email/{email}")
    @ApiOperation(value = "Lista entradas por correo electronico")
    @ApiResponses({
            @ApiResponse(code = 200, message = "Listado por correo", response = Ticket.class, responseContainer = "List"),
            @ApiResponse(code = 400, message = "Correo invalido")
    })
    public Response listTicketsByEmail(@PathParam("email") String email) {
        try {
            List<Ticket> tickets = manager().listTicketsByEmail(email);
            GenericEntity<List<Ticket>> entity = new GenericEntity<List<Ticket>>(tickets) {
            };
            return Response.ok(entity).build();
        } catch (SQLException ex) {
            throw dbError(ex, "Error al consultar la base de datos");
        }
    }

    @GET
    @Path("/tickets/used")
    @ApiOperation(value = "Lista todas las entradas usadas")
    @ApiResponses({
            @ApiResponse(code = 200, message = "Listado de entradas usadas", response = Ticket.class, responseContainer = "List")
    })
    public Response listUsedTickets() {
        try {
            List<Ticket> tickets = manager().listUsedTickets();
            GenericEntity<List<Ticket>> entity = new GenericEntity<List<Ticket>>(tickets) {
            };
            return Response.ok(entity).build();
        } catch (SQLException ex) {
            throw dbError(ex, "Error al consultar la base de datos");
        }
    }

    @GET
    @Path("/tickets/unused")
    @ApiOperation(value = "Lista todas las entradas no usadas")
    @ApiResponses({
            @ApiResponse(code = 200, message = "Listado de entradas no usadas", response = Ticket.class, responseContainer = "List")
    })
    public Response listUnusedTickets() {
        try {
            List<Ticket> tickets = manager().listUnusedTickets();
            GenericEntity<List<Ticket>> entity = new GenericEntity<List<Ticket>>(tickets) {
            };
            return Response.ok(entity).build();
        } catch (SQLException ex) {
            throw dbError(ex, "Error al consultar la base de datos");
        }
    }

    private ApiException dbError(SQLException ex, String message) {
        String detail = ex.getMessage();
        if (detail == null || detail.trim().isEmpty()) {
            detail = ex.getClass().getSimpleName();
        }
        return new ApiException(500, "DB_ERROR", message + ": " + detail);
    }

    private EventManager manager() {
        EventManager current = this.eventManager;
        if (current != null) {
            return current;
        }

        synchronized (this) {
            if (this.eventManager == null) {
                try {
                    this.eventManager = new EventManager(TicketRepositoryFactory.create());
                } catch (RuntimeException ex) {
                    throw new ApiException(500, "DB_CONFIG_ERROR", "Error de configuracion de MongoDB: " + rootMessage(ex));
                }
            }
            return this.eventManager;
        }
    }

    private String rootMessage(Throwable throwable) {
        Throwable current = throwable;
        while (current.getCause() != null) {
            current = current.getCause();
        }
        String message = current.getMessage();
        if (message == null || message.trim().isEmpty()) {
            return current.getClass().getSimpleName();
        }
        return message;
    }
}

package edu.upc.dsa.models.dto;

public class TokenDTO {
    private String token;

    public TokenDTO() {}

    public TokenDTO(String token) { this.token = token; }

    public String getToken() { return token; }
    public void setToken(String token) { this.token = token; }
}

CREATE DATABASE IF NOT EXISTS qr_app CHARACTER SET utf8mb4 COLLATE utf8mb4_spanish_ci;
SET NAMES utf8mb4; USE qr_app;
CREATE TABLE IF NOT EXISTS event_tickets ( id BIGINT AUTO_INCREMENT PRIMARY KEY, nombre VARCHAR(120) NOT NULL, apellido VARCHAR(120) NOT NULL, correo_electronico VARCHAR(255) NOT NULL, tipo TINYINT NOT NULL, pmr BOOLEAN NOT NULL DEFAULT FALSE, hash VARCHAR(128) NOT NULL UNIQUE, numero_local INT NOT NULL, consumed BOOLEAN NOT NULL DEFAULT FALSE, consumed_at DATETIME NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, INDEX idx_event_tickets_email (correo_electronico), INDEX idx_event_tickets_consumed (consumed), CHECK (tipo BETWEEN 0 AND 4) ) CHARACTER SET utf8mb4 COLLATE utf8mb4_spanish_ci;

package edu.upc.dsa.event.service;

import edu.upc.dsa.event.exception.ApiException;
import edu.upc.dsa.event.model.Ticket;
import edu.upc.dsa.event.repository.InMemoryTicketRepository;
import org.junit.Before;
import org.junit.Test;

import java.util.List;

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertTrue;

public class EventManagerTest {

    private EventManager eventManager;

    @Before
    public void setUp() {
        InMemoryTicketRepository repository = new InMemoryTicketRepository();
        repository.upsert(new Ticket(
                "Leonardo",
                "Andreoli",
                "delegacio.eetac@upc.edu",
                4,
                false,
                "HnmdIOCoTKusuKcCSyQCugr9v30fcQ5J",
                2,
                false
        ));
        repository.upsert(new Ticket(
                "Ada",
                "Lovelace",
                "ada@example.com",
                0,
                true,
                "USED_HASH",
                1,
                true
        ));
        this.eventManager = new EventManager(repository);
    }

    @Test
    public void verifyShouldReturnTicketByHash() throws Exception {
        Ticket ticket = eventManager.verify("HnmdIOCoTKusuKcCSyQCugr9v30fcQ5J");
        assertEquals("Leonardo", ticket.getNombre());
        assertEquals(4, ticket.getTipo());
    }

    @Test
    public void enterShouldConsumeTicket() throws Exception {
        Ticket consumed = eventManager.enter("HnmdIOCoTKusuKcCSyQCugr9v30fcQ5J");
        assertTrue(consumed.isConsumed());
        assertTrue(consumed.getConsumedAt() != null && !consumed.getConsumedAt().isEmpty());
    }

    @Test(expected = ApiException.class)
    public void enterShouldFailIfAlreadyConsumed() throws Exception {
        eventManager.enter("USED_HASH");
    }

    @Test
    public void listAllShouldReturnAllTickets() throws Exception {
        List<Ticket> tickets = eventManager.listAllTickets();
        assertEquals(2, tickets.size());
    }

    @Test
    public void listByEmailShouldFilterTickets() throws Exception {
        List<Ticket> tickets = eventManager.listTicketsByEmail("ada@example.com");
        assertEquals(1, tickets.size());
        assertEquals("USED_HASH", tickets.get(0).getHash());
    }

    @Test
    public void listUsedShouldReturnOnlyConsumedTickets() throws Exception {
        List<Ticket> tickets = eventManager.listUsedTickets();
        assertEquals(1, tickets.size());
        assertTrue(tickets.get(0).isConsumed());
    }

    @Test
    public void listUnusedShouldReturnOnlyAvailableTickets() throws Exception {
        List<Ticket> tickets = eventManager.listUnusedTickets();
        assertEquals(1, tickets.size());
        assertEquals("HnmdIOCoTKusuKcCSyQCugr9v30fcQ5J", tickets.get(0).getHash());
    }
}
